                 return (
                   <CommandItem
                     key={String(val)}
                     onSelect={() => {
                       field.onChange(val);
                       setOpen(false);
                     }}
                     value={getLabel(option)}
                   >
                     <span className="truncate">{getLabel(option)}</span>
                   </CommandItem>
                 );
               })}
             </CommandGroup>
           </CommandList>
         </Command>
